texttool_globals_dialog_message___developer_options_not_available = TextObject(bs_BA="Opcije programera nisu raspoložive.", cs_CZ="Vývojářské možnosti jsou nedostupné.", da_DK="Udvikleroptioner ikke tilgængelige.", de_DE="Entwickleroptionen sind nicht verfügbar.", el_GR="Επιλογές προγραμματιστή δεν είναι διαθέσιμες.", en_GB="Developer options are not available.", es_ES="Las opciones de desarrollo no están disponibles.", fi_FI="Kehitysvaihtoehdot eivät ole käytettävissä.", fr_FR="Les options pour les développeurs ne sont pas disponibles.", hr_HR="Opcije za razvoj nisu raspoložive.", hu_HU="Fejlesztői lehetőségek nem állnak rendelkezésre.", it_IT="Le opzioni per gli sviluppatori non sono disponibili.", nl_NL="Ontwikkelaarsopties zijn niet beschikbaar.", no_NO="Utvikleralternativer er ikke tilgjengelige.", pl_PL="Opcje programisty są niedostępne.", pt_PT="Opções de desenvolvimento não estão disponíveis.", ro_RO="Opţiunile pentru dezvoltatori nu sunt disponibile.", ru_RU="Параметры разработчика недоступны.", sk_SK="Možnosti pre vývojárov nie sú k dispozícii.", sl_SI="Možnosti za razvijalce niso na voljo.", sr_RS="Opcije kreatora nisu dostupne.", sv_SE="Utvecklaralternativ är inte tillgängliga.", tr_TR="Geliştirici seçenekleri mevcut değil.", uk_UA="Параметри розробника недоступні.")
